    public static File createAndCheckFolder(String path, boolean dryRun) {
        File f = new File(path);

        if (dryRun) {
            return f;
        }

        if (!f.exists()) {
            f.mkdirs();
        }

        if (!f.exists() || !f.isDirectory()) {
            throw new IllegalStateException("could not create folder: " + path);
        }
        return f;
    }

